import { workflow, trigger, node } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const setNode = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'full execution test',
    parameters: {
      assignments: {
        assignments: [
          {
            id: 'sample-field',
            name: 'status',
            value: 'ok',
            type: 'string'
          }
        ]
      }
    }
  }
});

export default workflow('end-to-end-test', 'End-to-End Execution Test')
  .add(manualTrigger)
  .to(setNode);
